                                     >Saldo Final</label\r\n                                        >\r\n                                        <el-input\r\n                                            readonly\r\n                                            v-model=\"final_balance\"\r\n                                        ></el-input>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </form>\r\n                </span>\r\n                <span slot=\"footer\" class=\"dialog-footer\">\r\n                    <el-button @click=\"closeDialog()\">Cerrar</el-button>\r\n                    <el-button type=\"primary\" @click=\"clickCloseCash()\"\r\n                        >Guardar</el-button\r\n                    >\r\n                </span>\r\n            </el-dialog>\r\n        </div>\r\n    </div>\r\n</template>\r\n<style>\r\n/* .el-input__inner {\r\n    padding: 0 25px !important;\r\n} */\r\n</style>\r\n<script>\r\n//'../../../../components/DataTable.vue'\r\nimport { deletable } from \"../../../../../../../resources/js/mixins/deletable\";\r\n///mixins/deletable'\r\nimport CashForm from \"./form.vue\";\r\n\r\nexport default {\r\n    mixins: [deletable],\r\n    props: [\"showDialogClose\", \"recordId\", \"fromBox\"],\r\n    data() {\r\n        return {\r\n            total: 0,\r\n            count: {},\r\n            showDialog: false,\r\n            open_cash: true,\r\n            errors: {},\r\n            resource: \"restaurant/worker/cash\",\r\n            date_closed: moment().format(\"YYYY-MM-DD\"),\r\n            date_start: moment().format(\"YYYY-MM-DD\"),\r\n            month_start: moment().format(\"YYYY-MM\"),\r\n            final_balance: 0,\r\n            cash: null,\r\n            loading: false\r\n        };\r\n    },\r\n\r\n    methods: {\r\n        ocultarBoton() {\r\n            this.$emit(\"ocultarBoton\");\r\n        },\r\n        sumCount() {\r\n            let sum = 0;\r\n            for (const amount in this.count) {\r\n                if (this.count[amount] > 0) {\r\n                    sum +=\r\n                        (Number(this.count[amount]) || 0) *\r\n                        (Number(amount) || 0);\r\n                } else {\r\n                    delete this.count[amount];\r\n                }\r\n            }\r\n            return sum;\r\n        },\r\n        updateFinalBalance(quantity, value) {\r\n            this.count[value.toString()] = quantity;\r\n\r\n            this.final_balance = _.round(this.sumCount(), 2);\r\n        },\r\n        clickCloseCash() {\r\n            const h = this.$createElement;\r\n            this.$msgbox({\r\n                title: \"Cerrar caja\",\r\n                type: \"warning\",\r\n                message: h(\"p\", null, [\r\n                    h(\r\n                        \"p\",\r\n                        { style: \"text-align: justify; font-size:15px\" },\r\n                        \"¿Está seguro de cerrar la caja?\"\r\n                    )\r\n                ]),\r\n\r\n                showCancelButton: true,\r\n                confirmButtonText: \"Aceptar\",\r\n                cancelButtonText: \"Cancelar\",\r\n                beforeClose: (action, instance, done) => {\r\n                    if (action === \"confirm\") {\r\n                        //  console.log(this.count);\r\n                        this.createRegister(instance, done);\r\n                    } else {\r\n                        done();\r\n                    }\r\n                }\r\n            })\r\n                .then(action => {})\r\n                .catch(action => {});\r\n        },\r\n        async dateclosed(date_closed) {\r\n            this.loading = true;\r\n            await this.$http\r\n                .get(`/restaurant/cash/balance-final/${this.date_closed}`)\r\n                .then(response => {\r\n                    //  this.final_balance = response.data.balance_total.toFixed(2);\r\n                    this.loading = false;\r\n                });\r\n        },\r\n        closeDialog() {\r\n            this.$emit(\"update:showDialogClose\", false);\r\n            this.count = {};\r\n            this.final_balance = 0;\r\n        },\r\n        async createRegister(instance, done) {\r\n            const body = {\r\n                id: this.recordId,\r\n                final_balance: this.final_balance,\r\n                counter: this.count\r\n            };\r\n            try {\r\n                const response = await this.$http.post(\r\n                    `/${this.resource}/close`,\r\n                    body\r\n                );\r\n\r\n                if (response.data.success) {\r\n                    this.$eventHub.$emit(\"reloadData\");\r\n                    this.open_cash = true;\r\n                    this.$toast.success(response.data.message);\r\n                    this.ocultarBoton();\r\n                    if (this.fromBox) {\r\n                        this.$emit(\"updateCashId\", null);\r\n                    }\r\n                } else {\r\n                    console.log(response);\r\n                }\r\n            } catch (error) {\r\n                console.log(error);\r\n            } finally {\r\n                instance.confirmButtonLoading = false;\r\n                instance.confirmButtonText = \"Iniciar prueba\";\r\n                done();\r\n            }\r\n\r\n            instance.confirmButtonLoading = true;\r\n            instance.confirmButtonText = \"Cerrando caja...\";\r\n            window.open(\r\n                `/restaurant/report-boxes/reports_resumen_type?cash_id=${this.recordId}`,\r\n                \"_blank\"\r\n            );\r\n            this.closeDialog();\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/cash/closecash.vue","<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        @close=\"close\"\r\n        @open=\"create\"\r\n        :data-keyboard=\"false\"\r\n        :closeOnPressEscape=\"dontClose\"\r\n        :closeOnClickModal=\"dontClose\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-6\">\r\n                        <div class=\"form-group\">\r\n                            <label class=\"control-label\">Cajero </label>\r\n                            <!--<el-input v-model=\"form.user\" readonly> <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input> -->\r\n                            <el-select\r\n                                :disabled=\"disableUser\"\r\n                                v-model=\"form.user_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in users\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.name\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.user\"\r\n                                v-text=\"errors.user[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.beginning_balance }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Saldo inicial de Apertura\r\n                            </label>\r\n                            <el-input v-model=\"form.beginning_balance\">\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.beginning_balance\"\r\n                                v-text=\"errors.beginning_balance[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.reference_number }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Seleccionar Turno de Apertura</label\r\n                            >\r\n                            <el-select v-model=\"form.turn_id\">\r\n                                <el-option\r\n                                    v-for=\"option in turnsTable\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.turn_desc\"\r\n                                ></el-option>\r\n                            </el-select>\r\n\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.reference_number\"\r\n                                v-text=\"errors.reference_number[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"showDialog\", \"recordId\", \"typeUser\", \"fromBox\"],\r\n    data() {\r\n        return {\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            resource: \"restaurant/worker/cash\",\r\n            errors: {},\r\n            form: {},\r\n            user: {},\r\n            all_departments: [],\r\n            all_provinces: [],\r\n            all_districts: [],\r\n            provinces: [],\r\n            districts: [],\r\n            identity_document_types: [],\r\n            users: [],\r\n            turnsTable: [],\r\n            dontClose: false\r\n        };\r\n    },\r\n    async created() {\r\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.users = response.data.users;\r\n            this.user = response.data.user;\r\n            this.turnsTable = response.data.turnsTable;\r\n        });\r\n\r\n        this.initForm();\r\n    },\r\n    computed: {\r\n        disableUser() {\r\n            if (this.typeUser == \"admin\" || this.typeUser === \"superadmin\") {\r\n                return false;\r\n            }\r\n            return true;\r\n        }\r\n    },\r\n    methods: {\r\n        ocultarBoton() {\r\n            this.$emit(\"ocultarBoton\");\r\n        },\r\n\r\n        initForm() {\r\n            this.errors = {};\r\n            this.form = {\r\n                id: null,\r\n                user_id: this.user.id,\r\n                // user: null,\r\n                date_opening: null,\r\n                time_opening: null,\r\n                date_closed: null,\r\n                time_closed: null,\r\n                beginning_balance: 0,\r\n                final_balance: 0,\r\n                income: 0,\r\n                state: true,\r\n                reference_number: null\r\n            };\r\n        },\r\n        create() {\r\n            this.titleDialog = this.recordId ? \"Editar Caja\" : \"Aperturar Caja\";\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n                    });\r\n            } else {\r\n                this.form.user_id = this.user.id; //sesion\r\n                //this.form.user = this.user.name\r\n            }\r\n        },\r\n        async openingCashCkeck() {\r\n            let response = await this.$http.get(\r\n                `/${this.resource}/opening_cash_check/${this.form.user_id}`\r\n            );\r\n\r\n            let cash = response.data.cash;\r\n            return cash ? true : false;\r\n        },\r\n        async submit() {\r\n            this.loading_submit = true;\r\n\r\n            if (this.form.turn_id == undefined) {\r\n                this.$toast.warning(\r\n                    `La opcion 'Seleccionar turno de apertura' no puede ser un campo vacio, por favor seleccione una opcion`\r\n                );\r\n\r\n                this.loading_submit = false;\r\n                return false;\r\n            }\r\n            if (!this.recordId) {\r\n                if (await this.openingCashCkeck()) {\r\n                    this.$toast.warning(\r\n                        \"No puede crear caja, porfavor cierre caja para el usuario definido\"\r\n                    );\r\n\r\n                    this.loading_submit = false;\r\n                    return false;\r\n                }\r\n            }\r\n\r\n            this.$http\r\n                .post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    console.log(response);\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        if (this.form.user_id === this.user.id)\r\n                            this.$eventHub.$emit(\"openCash\");\r\n                        this.$eventHub.$emit(\"reloadData\");\r\n                        if (this.fromBox) {\r\n                            this.$emit(\"updateCashId\", response.data.cash_id);\r\n                        }\r\n                        // window.open('/pos/init')\r\n                        this.close();\r\n                        this.ocultarBoton();\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.initForm();\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/cash/form.vue","exports = module.exports = require(\"../../../../../../../node_modules/css-loader/lib/css-base.js\")(true);\n// imports\n\n\n// module\nexports.push([module.id, \"\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n\\n